diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 60da48e1d95d..a34f78715cfa 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -5668,6 +5668,64 @@ Instruction *InstCombinerImpl::foldICmpWithMinMax(Instruction &I,
   // -46, -32)`. `X` is allowed to be non-negative here.
   Pred = Pred.dropSameSign();
   auto CmpXZ = IsCondKnownTrue(simplifyICmpInst(Pred, X, Z, Q));
+  // Try to fold icmp eq/ne Z, min(max(Z, C1), C2) into a range check.
+  // For signed: smin(smax(Z, C1), C2) checks if Z is in [C1, C2].
+  // For unsigned: umin(umax(Z, C1), C2) checks if Z is in [C1, C2].
+  // Also handle the swapped form: max(min(Z, C1), C2).
+  if (CmpInst::isEquality(Pred)) {
+    auto MatchClampPattern = [&](Value *Inner, Value *OuterC,
+                                 const APInt *&CInner,
+                                 const APInt *&COuter) -> bool {
+      auto *InnerMM = dyn_cast<MinMaxIntrinsic>(Inner);
+      if (!InnerMM || InnerMM->isSigned() != MinMax->isSigned())
+        return false;
+      if (!match(OuterC, m_APInt(COuter)))
+        return false;
+
+      // Determine if outer is min or max, and inner should be the opposite.
+      bool OuterIsMin = MinMax->getIntrinsicID() == Intrinsic::smin ||
+                        MinMax->getIntrinsicID() == Intrinsic::umin;
+      bool InnerIsMax = InnerMM->getIntrinsicID() == Intrinsic::smax ||
+                        InnerMM->getIntrinsicID() == Intrinsic::umax;
+      if (OuterIsMin != InnerIsMax)
+        return false;
+
+      // Check if Z is one operand of InnerMM and the other is a constant.
+      if (InnerMM->getLHS() == Z && match(InnerMM->getRHS(), m_APInt(CInner)))
+        return true;
+      if (InnerMM->getRHS() == Z && match(InnerMM->getLHS(), m_APInt(CInner)))
+        return true;
+      return false;
+    };
+
+    const APInt *C1, *C2;
+    if (MatchClampPattern(X, Y, C1, C2) ||
+        MatchClampPattern(Y, X, C1, C2)) {
+      // We have Z == clamp(Z, C1, C2) or Z != clamp(Z, C1, C2).
+      // This is a range check: Z is in [C1, C2] (inclusive).
+      // Convert to: (Z - C1) u<= (C2 - C1) for eq.
+      // Or: (Z - C1) u> (C2 - C1) for ne.
+      bool IsEQ = Pred == ICmpInst::ICMP_EQ;
+      APInt Delta = *C2 - *C1;
+      // For unsigned range check to work, we need to check if C1 <= C2
+      // in the signed/unsigned sense as appropriate.
+      // If C1 > C2 in the relevant sense, the range is empty.
+      bool C1_LE_C2 = MinMax->isSigned() ? C1->sle(*C2) : C1->ule(*C2);
+      if (C1_LE_C2) {
+        // C1 <= C2, range is non-empty.
+        // (Z - C1) u<= Delta for eq, (Z - C1) u> Delta for ne.
+        Value *Add = Builder.CreateAdd(Z, ConstantInt::get(Z->getType(), -(*C1)));
+        ICmpInst::Predicate NewPred =
+            IsEQ ? ICmpInst::ICMP_ULE : ICmpInst::ICMP_UGT;
+        return new ICmpInst(NewPred, Add,
+                            ConstantInt::get(Z->getType(), Delta));
+      }
+      // If C1 > C2, the range is empty: icmp eq is always false, ne always true.
+      return replaceInstUsesWith(
+          I, ConstantInt::getBool(I.getType(), !IsEQ));
+    }
+  }
+
   auto CmpYZ = IsCondKnownTrue(simplifyICmpInst(Pred, Y, Z, Q));
   if (!CmpXZ.has_value() && !CmpYZ.has_value())
     return nullptr;

